use std::collections::HashMap;
use std::fs;

struct KvStore { data: HashMap<String, String>, path: String }

impl KvStore {
    pub fn open(path: String) -> Self {
        let data = if std::path::Path::new(&path).exists() {
            let raw = fs::read_to_string(&path).unwrap_or_default();
            serde_json::from_str(&raw).unwrap_or_default()
        } else { HashMap::new() };
        Self { data, path }
    }
    pub fn get(&self, key: &str) -> Option<String> { self.data.get(key).cloned() }
    pub fn set(&mut self, key: String, value: String) { self.data.insert(key, value); }
    pub fn delete(&mut self, key: &str) -> bool { self.data.remove(key).is_some() }
    pub fn list(&self) -> Vec<String> { self.data.keys().cloned().collect() }
    pub fn save(&self) { let s = serde_json::to_string(&self.data).unwrap(); fs::write(&self.path, s).unwrap(); }
    pub fn len(&self) -> usize { self.data.len() }
}

fn main() {
    let mut store = KvStore::open("store.json".into());
    store.set("name".into(), "MechGen".into());
    store.set("version".into(), "0.1".into());
    println!("Keys: {}", store.list().join(", "));
    println!("name = {}", store.get("name").unwrap());
    store.save();
}

