            }
        } : {
            ? line.starts_with("```") {
                html.push("<pre><code>".to_string());
                in_code_block = 1b;
            } : ? line.starts_with("### ") {
                html.push(f"<h3>{inline_fmt(&line[4..])}</h3>");
            } : ? line.starts_with("## ") {
                html.push(f"<h2>{inline_fmt(&line[3..])}</h2>");
            } : ? line.starts_with("# ") {
                html.push(f"<h1>{inline_fmt(&line[2..])}</h1>");
            } : ? line.trim().is_empty() {
                html.push("".to_string());
            } : {
                html.push(f"<p>{inline_fmt(line)}</p>");
            }
        }
    }
    @HtmlDoc { body: html.join("\n") }
}

f inline_fmt(text: &s) -> s {
    m result = text.to_string();
    // Bold **text**
    loop {
        v start = result.find("**");
        ? start {
            ?None => break,
            ?Some(s) => {
                v end = result[s+2..].find("**");
                ? end {
                    ?None => break,
                    ?Some(e) => {
                        v inner = result[s+2..s+2+e].to_string();
                        result = f"{result[..s]}<strong>{inner}</strong>{result[s+2+e+2..]}";
                    },
                }
            },
        }
    }
    result
}

f escape_html(text: &s) -> s {
    text.replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
}

