pub fn md_to_html(markdown: &str) -> HtmlDoc {
    let mut html = Vec::new();
    let mut in_code_block = false;
    for line in markdown.lines() {
        if in_code_block {
            if line.starts_with("```") { html.push("</code></pre>".into()); in_code_block = false; }
            else { html.push(escape_html(line)); }
        } else if line.starts_with("```") {
            html.push("<pre><code>".into()); in_code_block = true;
        } else if line.starts_with("### ") {
            html.push(format!("<h3>{}</h3>", inline_fmt(&line[4..])));
        } else if line.starts_with("## ") {
            html.push(format!("<h2>{}</h2>", inline_fmt(&line[3..])));
        } else if line.starts_with("# ") {
            html.push(format!("<h1>{}</h1>", inline_fmt(&line[2..])));
        } else if line.trim().is_empty() {
            html.push(String::new());
        } else {
            html.push(format!("<p>{}</p>", inline_fmt(line)));
        }
    }
    HtmlDoc { body: html.join("\n") }
}

fn inline_fmt(text: &str) -> String {
    let mut result = text.to_string();
    while let Some(s) = result.find("**") {
        if let Some(e) = result[s+2..].find("**") {
            let inner = result[s+2..s+2+e].to_string();
            result = format!("{}<strong>{}</strong>{}", &result[..s], inner, &result[s+2+e+2..]);
        } else { break; }
    }
    result
}

fn escape_html(text: &str) -> String {
    text.replace('&', "&amp;").replace('<', "&lt;").replace('>', "&gt;")
}

