S Task {
    id: u32,
    name: s,
    priority: u32,
    deadline: u64,
    status: TaskStatus,
}

S Scheduler {
    tasks: [Task]~,
    next_id: u32,
    current_time: u64,
}

I Scheduler {
    +f new(time: u64) -> Scheduler {
        @Scheduler { tasks: [], next_id: 1, current_time: time }
    }
    +f add(&!self, name: s, priority: u32, deadline: u64) -> u32 {
        v id = self.next_id;
        self.tasks.push(@Task {
            id: id, name: name, priority: priority,
            deadline: deadline, status: TaskStatus.Pending,
        });
        self.next_id = self.next_id + 1;
        id
    }
    +f next(&!self) -> ?&!Task {
        v best_idx: ?usize = ?None;
        v best_priority: u32 = 0;
        m i: usize = 0;
        @ task : &self.tasks {
            ? task.status == TaskStatus.Pending && task.priority > best_priority {
                best_priority = task.priority;
                best_idx = ?Some(i);
            }
            i = i + 1;
        }
        ? best_idx {
            ?Some(idx) => {
                self.tasks[idx].status = TaskStatus.Running;
                ?Some(&!self.tasks[idx])
            },
            ?None => ?None,
        }
    }
    +f complete(&!self, id: u32) {
        @ task : &!self.tasks {
            ? task.id == id { task.status = TaskStatus.Done; }
        }
    }
    +f overdue(&self) -> [&Task]~ {
        self.tasks.iter()
            .filter(fn(t) => t.status == TaskStatus.Pending && t.deadline < self.current_time)
            .to_vec()
    }
    +f tick(&!self, new_time: u64) { self.current_time = new_time; }
}

