#[derive(PartialEq)]
enum TaskStatus { Pending, Running, Done, Failed }
struct Task { id: u32, name: String, priority: u32, deadline: u64, status: TaskStatus }
struct Scheduler { tasks: Vec<Task>, next_id: u32, current_time: u64 }

impl Scheduler {
    pub fn new(time: u64) -> Self { Self { tasks: Vec::new(), next_id: 1, current_time: time } }
    pub fn add(&mut self, name: String, priority: u32, deadline: u64) -> u32 {
        let id = self.next_id;
        self.tasks.push(Task { id, name, priority, deadline, status: TaskStatus::Pending });
        self.next_id += 1;
        id
    }
    pub fn next(&mut self) -> Option<&mut Task> {
        let mut best_idx = None;
        let mut best_priority = 0;
        for (i, task) in self.tasks.iter().enumerate() {
            if task.status == TaskStatus::Pending && task.priority > best_priority {
                best_priority = task.priority; best_idx = Some(i);
            }
        }
        if let Some(idx) = best_idx { self.tasks[idx].status = TaskStatus::Running; Some(&mut self.tasks[idx]) }
        else { None }
    }
    pub fn complete(&mut self, id: u32) {
        for task in &mut self.tasks { if task.id == id { task.status = TaskStatus::Done; } }
    }
    pub fn overdue(&self) -> Vec<&Task> {
        self.tasks.iter().filter(|t| t.status == TaskStatus::Pending && t.deadline < self.current_time).collect()
    }
    pub fn tick(&mut self, new_time: u64) { self.current_time = new_time; }
}

