E Expr {
    Num(f64),
    Var(s),
    BinOp(^Expr, s, ^Expr),
    Call(s, [Expr]~),
}

E Value {
    Num(f64),
    Bool(bool),
}

S Env {
    vars: {s: Value},
    funcs: {s: f([Value]~) -> R[Value, s]},
}

I Env {
    +f new() -> Env { @Env { vars: {}, funcs: {} } }
    +f set_var(&!self, name: s, val: Value) { self.vars.insert(name, val); }
    +f set_func(&!self, name: s, func: f([Value]~) -> R[Value, s]) { self.funcs.insert(name, func); }
}

+f eval(expr: &Expr, env: &Env) -> R[Value, s] {
    ? expr {
        Expr.Num(n) => R.Ok(Value.Num(*n)),
        Expr.Var(name) => ? env.vars.get(name) {
            ?Some(v) => R.Ok(v.clone()),
            ?None => R.Err(f"undefined variable: {name}"),
        },
        Expr.BinOp(lhs, op, rhs) => {
            v l = eval(lhs, env)?;
            v r = eval(rhs, env)?;
            ? (l, op.as_str(), r) {
                (Value.Num(a), "+", Value.Num(b)) => R.Ok(Value.Num(a + b)),
                (Value.Num(a), "-", Value.Num(b)) => R.Ok(Value.Num(a - b)),
                (Value.Num(a), "*", Value.Num(b)) => R.Ok(Value.Num(a * b)),
                (Value.Num(a), "/", Value.Num(b)) => ? b != 0.0 {
                    R.Ok(Value.Num(a / b))
                } : { R.Err("division by zero") },
                (Value.Num(a), "==", Value.Num(b)) => R.Ok(Value.Bool(a == b)),
                (Value.Num(a), "<", Value.Num(b)) => R.Ok(Value.Bool(a < b)),
                _ => R.Err(f"invalid op: {op}"),
            }
        },
        Expr.Call(name, args) => {
            m evaluated: [Value]~ = [];
            @ arg : args { evaluated.push(eval(arg, env)?); }
            ? env.funcs.get(name) {
                ?Some(func) => func(evaluated),
                ?None => R.Err(f"undefined function: {name}"),
            }
        },
    }
}

