use std::collections::HashMap;

enum Expr { Num(f64), Var(String), BinOp(Box<Expr>, String, Box<Expr>), Call(String, Vec<Expr>) }
#[derive(Clone)]
enum Value { Num(f64), Bool(bool) }
struct Env {
    vars: HashMap<String, Value>,
    funcs: HashMap<String, fn(Vec<Value>) -> Result<Value, String>>,
}

impl Env {
    pub fn new() -> Self { Self { vars: HashMap::new(), funcs: HashMap::new() } }
    pub fn set_var(&mut self, name: String, val: Value) { self.vars.insert(name, val); }
    pub fn set_func(&mut self, name: String, func: fn(Vec<Value>) -> Result<Value, String>) { self.funcs.insert(name, func); }
}

pub fn eval(expr: &Expr, env: &Env) -> Result<Value, String> {
    match expr {
        Expr::Num(n) => Ok(Value::Num(*n)),
        Expr::Var(name) => env.vars.get(name).cloned().ok_or(format!("undefined variable: {}", name)),
        Expr::BinOp(lhs, op, rhs) => {
            let l = eval(lhs, env)?;
            let r = eval(rhs, env)?;
            match (&l, op.as_str(), &r) {
                (Value::Num(a), "+", Value::Num(b)) => Ok(Value::Num(a + b)),
                (Value::Num(a), "-", Value::Num(b)) => Ok(Value::Num(a - b)),
                (Value::Num(a), "*", Value::Num(b)) => Ok(Value::Num(a * b)),
                (Value::Num(a), "/", Value::Num(b)) if *b != 0.0 => Ok(Value::Num(a / b)),
                (Value::Num(_), "/", Value::Num(_)) => Err("division by zero".into()),
                (Value::Num(a), "==", Value::Num(b)) => Ok(Value::Bool(a == b)),
                (Value::Num(a), "<", Value::Num(b)) => Ok(Value::Bool(a < b)),
                _ => Err(format!("invalid op: {}", op)),
            }
        }
        Expr::Call(name, args) => {
            let evaluated: Result<Vec<_>, _> = args.iter().map(|a| eval(a, env)).collect();
            match env.funcs.get(name) {
                Some(func) => func(evaluated?),
                None => Err(format!("undefined function: {}", name)),
            }
        }
    }
}

