    body: s,
}

I Response {
    +f ok(body: s) -> Response {
        @Response { status: 200, headers: {"content-type": "text/plain"}, body: body }
    }
    +f json(body: s) -> Response {
        @Response { status: 200, headers: {"content-type": "application/json"}, body: body }
    }
    +f not_found() -> Response {
        @Response { status: 404, headers: {}, body: "not found" }
    }
}

S Route {
    method: s,
    pattern: s,
    handler: f(&Request, &{s: s}) -> Response,
}

S Router {
    routes: [Route]~,
    middleware: [f(&Request, &!Response)]~,
}

I Router {
    +f new() -> Router { @Router { routes: [], middleware: [] } }
    +f get(&!self, pattern: s, handler: f(&Request, &{s: s}) -> Response) {
        self.routes.push(@Route { method: "GET", pattern: pattern, handler: handler });
    }
    +f post(&!self, pattern: s, handler: f(&Request, &{s: s}) -> Response) {
        self.routes.push(@Route { method: "POST", pattern: pattern, handler: handler });
    }
    +f use_mw(&!self, mw: f(&Request, &!Response)) { self.middleware.push(mw); }
    +f dispatch(&self, req: &Request) -> Response {
        @ route : &self.routes {
            ? route.method == req.method {
                v params = match_path(&route.pattern, &req.path);
                ? params {
                    ?Some(p) => {
                        m resp = (route.handler)(req, &p);
                        @ mw : &self.middleware { mw(req, &!resp); }
                        ret resp;
                    },
                    ?None => {},
                }
            }
        }
        Response.not_found()
    }
}

f match_path(pattern: &s, path: &s) -> ?{s: s} {
    v pat_parts = pattern.split('/').to_vec();
    v path_parts = path.split('/').to_vec();
    ? pat_parts.len() != path_parts.len() { ret ?None; }
    m params: {s: s} = {};
    m i: usize = 0;
    @ pp : &pat_parts {
        ? pp.starts_with(':') {
            params.insert(pp[1..].to_string(), path_parts[i].to_string());
        } : ? pp != &path_parts[i] {
            ret ?None;
        }
        i = i + 1;
    }
    ?Some(params)
}

