use std::collections::HashMap;

struct Request { method: String, path: String, headers: HashMap<String, String>, body: String }
struct Response { status: u16, headers: HashMap<String, String>, body: String }

impl Response {
    pub fn ok(body: String) -> Self { Self { status: 200, headers: [("content-type".into(), "text/plain".into())].into(), body } }
    pub fn json(body: String) -> Self { Self { status: 200, headers: [("content-type".into(), "application/json".into())].into(), body } }
    pub fn not_found() -> Self { Self { status: 404, headers: HashMap::new(), body: "not found".into() } }
}

struct Route { method: String, pattern: String, handler: fn(&Request, &HashMap<String, String>) -> Response }
struct Router { routes: Vec<Route>, middleware: Vec<fn(&Request, &mut Response)> }

impl Router {
    pub fn new() -> Self { Self { routes: Vec::new(), middleware: Vec::new() } }
    pub fn get(&mut self, pattern: String, handler: fn(&Request, &HashMap<String, String>) -> Response) {
        self.routes.push(Route { method: "GET".into(), pattern, handler });
    }
    pub fn dispatch(&self, req: &Request) -> Response {
        for route in &self.routes {
            if route.method == req.method {
                if let Some(params) = match_path(&route.pattern, &req.path) {
                    let mut resp = (route.handler)(req, &params);
                    for mw in &self.middleware { mw(req, &mut resp); }
                    return resp;
                }
            }
        }
        Response::not_found()
    }
}

fn match_path(pattern: &str, path: &str) -> Option<HashMap<String, String>> {
    let pat: Vec<&str> = pattern.split('/').collect();
    let parts: Vec<&str> = path.split('/').collect();
    if pat.len() != parts.len() { return None; }
    let mut params = HashMap::new();
    for (pp, actual) in pat.iter().zip(parts.iter()) {
        if pp.starts_with(':') { params.insert(pp[1..].to_string(), actual.to_string()); }
        else if pp != actual { return None; }
    }
    Some(params)
}

