S TokenRule {
    name: s,
    pattern: s,
}

S Token {
    kind: s,
    lexeme: s,
    offset: usize,
}

S Lexer {
    rules: [TokenRule]~,
    skip_whitespace: bool,
}

I Lexer {
    +f new(rules: [TokenRule]~) -> Lexer {
        @Lexer { rules: rules, skip_whitespace: 1b }
    }
    +f tokenize(&self, input: &s) -> R[[Token]~, s] {
        m tokens: [Token]~ = [];
        m pos: usize = 0;
        loop {
            ? pos >= input.len() { break; }
            ? self.skip_whitespace {
                loop {
                    ? pos < input.len() && input[pos..pos+1].trim().is_empty() {
                        pos = pos + 1;
                    } : { break; }
                }
            }
            ? pos >= input.len() { break; }
            m matched = 0b;
            @ rule : &self.rules {
                v m_result = try_match(&rule.pattern, &input[pos..]);
                ? m_result {
                    ?Some(lexeme) => {
                        tokens.push(@Token {
                            kind: rule.name.clone(),
                            lexeme: lexeme.clone(),
                            offset: pos,
                        });
                        pos = pos + lexeme.len();
                        matched = 1b;
                        break;
                    },
                    ?None => {},
                }
            }
            ? !matched {
                ret R.Err(f"unexpected char at offset {pos}: '{input[pos..pos+1]}'");
            }
        }
        R.Ok(tokens)
    }
}

f try_match(pattern: &s, input: &s) -> ?s {
    // Simple prefix match for literal patterns
    ? input.starts_with(pattern) {
        ?Some(pattern.to_string())
    } : { ?None }
}

