struct TokenRule { name: String, pattern: String }
struct Token { kind: String, lexeme: String, offset: usize }
struct Lexer { rules: Vec<TokenRule>, skip_whitespace: bool }

impl Lexer {
    pub fn new(rules: Vec<TokenRule>) -> Self { Self { rules, skip_whitespace: true } }
    pub fn tokenize(&self, input: &str) -> Result<Vec<Token>, String> {
        let mut tokens = Vec::new();
        let mut pos = 0;
        let bytes = input.as_bytes();
        while pos < bytes.len() {
            if self.skip_whitespace {
                while pos < bytes.len() && bytes[pos].is_ascii_whitespace() { pos += 1; }
            }
            if pos >= bytes.len() { break; }
            let mut matched = false;
            for rule in &self.rules {
                if input[pos..].starts_with(&rule.pattern) {
                    let lexeme = rule.pattern.clone();
                    tokens.push(Token { kind: rule.name.clone(), lexeme: lexeme.clone(), offset: pos });
                    pos += lexeme.len();
                    matched = true;
                    break;
                }
            }
            if !matched { return Err(format!("unexpected char at offset {}", pos)); }
        }
        Ok(tokens)
    }
}

