E Event { Incremented(u32), Decremented(u32), WasReset }

S CounterState {
    value: i64,
    version: u32,
}

S EventStore {
    events: [Event]~,
}

I EventStore {
    +f new() -> EventStore { @EventStore { events: [] } }
    +f append(&!self, event: Event) { self.events.push(event); }
    +f replay(&self) -> CounterState {
        m state = @CounterState { value: 0, version: 0 };
        @ event : &self.events {
            apply_event(&!state, event);
        }
        state
    }
    +f len(&self) -> usize { self.events.len() }
}

f apply_event(state: &!CounterState, event: &Event) {
    ? event {
        Event.Incremented(n) => { state.value = state.value + *n as i64; },
        Event.Decremented(n) => { state.value = state.value - *n as i64; },
        Event.WasReset => { state.value = 0; },
    }
    state.version = state.version + 1;
}

+f handle_command(store: &!EventStore, cmd: Command) -> R[(), s] {
    v event = ? cmd {
        Command.Increment(n) => Event.Incremented(n),
        Command.Decrement(n) => {
            v state = store.replay();
            ? state.value < n as i64 { ret R.Err("cannot go negative"); }
            Event.Decremented(n)
        },
        Command.Reset => Event.WasReset,
    };
    store.append(event);
    R.Ok(())
}

