enum Command { Increment(u32), Decrement(u32), Reset }
enum Event { Incremented(u32), Decremented(u32), WasReset }
struct CounterState { value: i64, version: u32 }
struct EventStore { events: Vec<Event> }

impl EventStore {
    pub fn new() -> Self { Self { events: Vec::new() } }
    pub fn append(&mut self, event: Event) { self.events.push(event); }
    pub fn replay(&self) -> CounterState {
        let mut state = CounterState { value: 0, version: 0 };
        for event in &self.events { apply_event(&mut state, event); }
        state
    }
    pub fn len(&self) -> usize { self.events.len() }
}

fn apply_event(state: &mut CounterState, event: &Event) {
    match event {
        Event::Incremented(n) => state.value += *n as i64,
        Event::Decremented(n) => state.value -= *n as i64,
        Event::WasReset => state.value = 0,
    }
    state.version += 1;
}

pub fn handle_command(store: &mut EventStore, cmd: Command) -> Result<(), String> {
    let event = match cmd {
        Command::Increment(n) => Event::Incremented(n),
        Command::Decrement(n) => {
            let state = store.replay();
            if state.value < n as i64 { return Err("cannot go negative".into()); }
            Event::Decremented(n)
        }
        Command::Reset => Event::WasReset,
    };
    store.append(event);
    Ok(())
}

