struct CsvRow { fields: Vec<String> }
struct CsvTable { headers: Vec<String>, rows: Vec<CsvRow> }

impl CsvTable {
    pub fn parse(input: &str) -> Result<Self, String> {
        let lines: Vec<&str> = input.lines().collect();
        if lines.is_empty() { return Err("empty CSV".into()); }
        let headers = parse_row(lines[0]);
        let mut rows = Vec::new();
        for (i, line) in lines[1..].iter().enumerate() {
            if !line.trim().is_empty() {
                let fields = parse_row(line);
                if fields.len() != headers.len() { return Err(format!("row {} has wrong number of fields", i+1)); }
                rows.push(CsvRow { fields });
            }
        }
        Ok(Self { headers, rows })
    }
    pub fn get(&self, row: usize, col: &str) -> Option<&str> {
        let ci = self.headers.iter().position(|h| h == col)?;
        self.rows.get(row).and_then(|r| r.fields.get(ci).map(|s| s.as_str()))
    }
    pub fn to_csv(&self) -> String {
        let mut lines = vec![self.headers.iter().map(|h| quote_field(h)).collect::<Vec<_>>().join(",")];
        for row in &self.rows { lines.push(row.fields.iter().map(|f| quote_field(f)).collect::<Vec<_>>().join(",")); }
        lines.join("\n")
    }
}

fn parse_row(line: &str) -> Vec<String> {
    let mut fields = Vec::new();
    let mut current = String::new();
    let mut in_quotes = false;
    for ch in line.chars() {
        if ch == '"' { in_quotes = !in_quotes; }
        else if ch == ',' && !in_quotes { fields.push(current.trim().to_string()); current.clear(); }
        else { current.push(ch); }
    }
    fields.push(current.trim().to_string());
    fields
}

fn quote_field(field: &str) -> String {
    if field.contains(',') || field.contains('"') { format!("\"{}\"", field.replace('"', "\"\"")) }
