I StateMachine {
    +f new(initial: s) -> StateMachine {
        @StateMachine {
            current: initial.clone(),
            transitions: [],
            history: [initial],
        }
    }
    +f add(&!self, from: s, event: s, to: s) {
        self.transitions.push(@Transition {
            from: from, event: event, to: to, guard: ?None,
        });
    }
    +f add_guarded(&!self, from: s, event: s, to: s, guard: f(&s) -> bool) {
        self.transitions.push(@Transition {
            from: from, event: event, to: to, guard: ?Some(guard),
        });
    }
    +f send(&!self, event: &s) -> R[&s, s] {
        @ t : &self.transitions {
            ? t.from == self.current && t.event == *event {
                v guard_ok = ? &t.guard {
                    ?Some(g) => g(&self.current),
                    ?None => 1b,
                };
                ? guard_ok {
                    self.current = t.to.clone();
                    self.history.push(self.current.clone());
                    ret R.Ok(&self.current);
                }
            }
        }
        R.Err(f"no transition from '{self.current}' on '{event}'")
    }
    +f state(&self) -> &s { &self.current }
    +f history(&self) -> &[s]~ { &self.history }
}

