struct Transition { from: String, event: String, to: String, guard: Option<fn(&str) -> bool> }
struct StateMachine { current: String, transitions: Vec<Transition>, history: Vec<String> }

impl StateMachine {
    pub fn new(initial: String) -> Self {
        Self { current: initial.clone(), transitions: Vec::new(), history: vec![initial] }
    }
    pub fn add(&mut self, from: String, event: String, to: String) {
        self.transitions.push(Transition { from, event, to, guard: None });
    }
    pub fn add_guarded(&mut self, from: String, event: String, to: String, guard: fn(&str) -> bool) {
        self.transitions.push(Transition { from, event, to, guard: Some(guard) });
    }
    pub fn send(&mut self, event: &str) -> Result<&str, String> {
        for t in &self.transitions {
            if t.from == self.current && t.event == event {
                let guard_ok = t.guard.map_or(true, |g| g(&self.current));
                if guard_ok {
                    self.current = t.to.clone();
                    self.history.push(self.current.clone());
                    return Ok(&self.current);
                }
            }
        }
        Err(format!("no transition from '{}' on '{}'", self.current, event))
    }
    pub fn state(&self) -> &str { &self.current }
    pub fn history(&self) -> &[String] { &self.history }
}

