E ServiceLifetime { Transient, Singleton }

S ServiceEntry {
    name: s,
    lifetime: ServiceLifetime,
    factory: f() -> ^dyn Any,
    singleton_cache: ?^dyn Any,
}

S Container {
    services: {s: ServiceEntry},
}

I Container {
    +f new() -> Container { @Container { services: {} } }
    +f register(
        &!self, name: s,
        lifetime: ServiceLifetime,
        factory: f() -> ^dyn Any,
    ) {
        self.services.insert(name.clone(), @ServiceEntry {
            name: name, lifetime: lifetime, factory: factory,
            singleton_cache: ?None,
        });
    }
    +f resolve(&!self, name: &s) -> R[^dyn Any, s] {
        v entry = self.services.get_mut(name);
        ? entry {
            ?Some(e) => {
                ? e.lifetime {
                    ServiceLifetime.Singleton => {
                        ? &e.singleton_cache {
                            ?Some(cached) => R.Ok(cached.clone()),
                            ?None => {
                                v instance = (e.factory)();
                                e.singleton_cache = ?Some(instance.clone());
                                R.Ok(instance)
                            },
                        }
                    },
                    ServiceLifetime.Transient => R.Ok((e.factory)()),
                }
            },
            ?None => R.Err(f"service not found: {name}"),
        }
    }
    +f has(&self, name: &s) -> bool {
        self.services.contains_key(name)
    }
    +f registered(&self) -> [s]~ {
        self.services.keys().to_vec()
    }
}

