use std::any::Any;
use std::collections::HashMap;

enum ServiceLifetime { Transient, Singleton }
struct ServiceEntry {
    name: String,
    lifetime: ServiceLifetime,
    factory: fn() -> Box<dyn Any>,
    singleton_cache: Option<Box<dyn Any>>,
}
struct Container { services: HashMap<String, ServiceEntry> }

impl Container {
    pub fn new() -> Self { Self { services: HashMap::new() } }
    pub fn register(&mut self, name: String, lifetime: ServiceLifetime, factory: fn() -> Box<dyn Any>) {
        self.services.insert(name.clone(), ServiceEntry { name, lifetime, factory, singleton_cache: None });
    }
    pub fn resolve(&mut self, name: &str) -> Result<Box<dyn Any>, String> {
        match self.services.get_mut(name) {
            Some(entry) => match entry.lifetime {
                ServiceLifetime::Singleton => {
                    if entry.singleton_cache.is_some() { Ok(entry.singleton_cache.clone().unwrap()) }
                    else { let i = (entry.factory)(); entry.singleton_cache = Some(i.clone()); Ok(i) }
                }
                ServiceLifetime::Transient => Ok((entry.factory)()),
            },
            None => Err(format!("service not found: {}", name)),
        }
    }
    pub fn has(&self, name: &str) -> bool { self.services.contains_key(name) }
}
